export function getGenreSongsForYear(genre: string, year: number): GenreSong[] {
  return genreBillboard[genre]?.[year] ?? []
}

export function getGenreYears(genre: string): number[] {
  return Object.keys(genreBillboard[genre] ?? {}).map(Number).sort()
}